import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"玩家常見問題","description":"關於 Fabric 的玩家和伺服器管理員常見問題解答手冊。","frontmatter":{"title":"玩家常見問題","description":"關於 Fabric 的玩家和伺服器管理員常見問題解答手冊。","search":false,"files":[]},"headers":[],"relativePath":"zh_tw/1.20.4/players/faq.md","filePath":"versions/1.20.4/translated/zh_tw/players/faq.md","lastUpdated":1739538073000}`);var a={name:`zh_tw/1.20.4/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">玩家常見問題 <a class="header-anchor" href="#h1" aria-label="Permalink to “玩家常見問題”">​</a></h1><p>有許多常見問題被頻繁地提出，所以我們在這裡整理了一份清單。</p><h2 id="一般問題" tabindex="-1">一般問題 <a class="header-anchor" href="#一般問題" aria-label="Permalink to “一般問題”">​</a></h2><h3 id="fabric-支援哪些-minecraft-版本" tabindex="-1">Fabric 支援哪些 Minecraft 版本？ <a class="header-anchor" href="#fabric-支援哪些-minecraft-版本" aria-label="Permalink to “Fabric 支援哪些 Minecraft 版本？”">​</a></h3><p>官方支援的 Fabric 版本包括從 <code>18w43b</code> 開始的所有快照版本，以及 <code>1.14</code> 及以上的正式版本。</p><h3 id="我在哪裡可以下載已發佈的-fabric-模組" tabindex="-1">我在哪裡可以下載已發佈的 Fabric 模組？ <a class="header-anchor" href="#我在哪裡可以下載已發佈的-fabric-模組" aria-label="Permalink to “我在哪裡可以下載已發佈的 Fabric 模組？”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>你都應該檢查模組是否來自可信賴的來源。 請參閱<a href="./finding-mods">尋找可信賴的模組</a>指南以獲得更多資訊。</p></div><p>大多數作者會將他們的模組發布到 <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> 和 <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>，但有些可能選擇將它們上傳到他們的個人網站，或者其他平台，如 GitHub 存儲庫。</p><h3 id="我在哪裡可以找到預製的-fabric-模組包" tabindex="-1">我在哪裡可以找到預製的 Fabric 模組包？ <a class="header-anchor" href="#我在哪裡可以找到預製的-fabric-模組包" aria-label="Permalink to “我在哪裡可以找到預製的 Fabric 模組包？”">​</a></h3><p>你可以在各種平台上找到預製的 Fabric 模組包，例如：</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,11)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};